// // This module implements an 8-bit register with asynchronous reset and disable.
module reg8_en (
    input clk,
    input reset,
    input enable,
    input [7:0] d,
    output reg [7:0] q);always @(posedge clk) begin
    if (reset)
        q <= 8'b0;
    else if (enable)
        q <= d;
end
endmodule
